def add_book(self, title, quantity=1):
    """
        Agrega uno o varios libros al inventario, que está ordenado por el título del libro.
        :param title: str, el título del libro
        :param quantity: int, el valor predeterminado es 1.
        """
    if not isinstance(title, str) or not isinstance(quantity, int) or quantity <= 0:
        raise ValueError('Invalid input: title must be a string and quantity must be a positive integer')
    if title in self.inventory:
        self.inventory[title] += quantity
    else:
        self.inventory[title] = quantity

def remove_book(self, title, quantity):
    """
        Eliminar uno o varios libros del inventario que está ordenado por título de libro.
        Lanza falso si se recibe una entrada no válida.
        :param title: str, el título del libro
        :param quantity: int
        """
    if not isinstance(title, str) or not isinstance(quantity, int):
        return False
    if quantity <= 0:
        return False
    if title not in self.inventory:
        return False
    if self.inventory[title] < quantity:
        return False
    self.inventory[title] -= quantity
    if self.inventory[title] == 0:
        del self.inventory[title]
    return True

def calculate(self, expression):
    """
        Calcula el valor de una expresión dada
        :param expression: cadena, expresión dada
        :return: Si tiene éxito, devuelve el valor de la expresión; de lo contrario, devuelve None
        >>> calculator = Calculator()
        >>> calculator.calculate('1+2-3')
        0.0
        """
    if not expression:
        return None
    expression = expression.replace(' ', '')
    if not expression:
        return None
    operand_stack = []
    operator_stack = []
    i = 0
    n = len(expression)
    while i < n:
        if expression[i].isdigit() or expression[i] == '.':
            j = i
            while j < n and (expression[j].isdigit() or expression[j] == '.'):
                j += 1
            try:
                num = float(expression[i:j])
            except ValueError:
                return None
            operand_stack.append(num)
            i = j
        elif expression[i] in self.operators:
            if i == 0 or expression[i - 1] in self.operators or expression[i - 1] == '(':
                if expression[i] == '-':
                    j = i + 1
                    while j < n and (expression[j].isdigit() or expression[j] == '.'):
                        j += 1
                    try:
                        num = float(expression[i + 1:j])
                    except ValueError:
                        return None
                    operand_stack.append(-num)
                    i = j
                    continue
                else:
                    return None
            while operator_stack and operator_stack[-1] != '(' and (self.precedence(operator_stack[-1]) >= self.precedence(expression[i])):
                self.apply_operator(operand_stack, operator_stack)
            operator_stack.append(expression[i])
            i += 1
        elif expression[i] == '(':
            operator_stack.append(expression[i])
            i += 1
        elif expression[i] == ')':
            while operator_stack and operator_stack[-1] != '(':
                self.apply_operator(operand_stack, operator_stack)
            if not operator_stack or operator_stack[-1] != '(':
                return None
            operator_stack.pop()
            i += 1
        else:
            return None
    while operator_stack:
        if operator_stack[-1] == '(':
            return None
        self.apply_operator(operand_stack, operator_stack)
    if len(operand_stack) != 1 or operator_stack:
        return None
    return operand_stack[0]

def register_student(self, student):
    """
        registrar un estudiante en el sistema, agregar el estudiante a la lista de estudiantes, si el estudiante ya está registrado, retornar 0, de lo contrario retornar 1
